import{_ as t,o as n,c as a,ae as r}from"./chunks/framework.z1tb74tW.js";const u=JSON.parse('{"title":"介绍","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/introduction.md","filePath":"zh/guide/introduction.md"}'),e={name:"zh/guide/introduction.md"};function i(l,o,s,g,d,c){return n(),a("div",null,[...o[0]||(o[0]=[r('<h1 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h1><p>NanoBoot 是一个轻量级的 Spring Boot 类似的微框架，专为 Java 开发而设计。它提供了诸如依赖注入、Web 开发、数据访问和 WebSocket 支持等核心功能，形成一个易于使用的模块化包。</p><h2 id="什么是-nanoboot" tabindex="-1">什么是 NanoBoot？ <a class="header-anchor" href="#什么是-nanoboot" aria-label="Permalink to &quot;什么是 NanoBoot？&quot;">​</a></h2><p>NanoBoot 是一个 Java 框架，借鉴了 Spring Boot 的设计理念，但更注重轻量化和模块化。它为开发人员提供了构建现代 Java 应用所需的核心功能，而无需庞大的 Spring 生态系统的开销。</p><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>依赖注入容器</strong>: 使用 <code>@Autowired</code> 进行自动装配</li><li><strong>注解处理</strong>: 支持 <code>@Component</code>、<code>@Service</code>、<code>@Controller</code> 等注解</li><li><strong>Web 框架</strong>: 内置 HTTP 服务器，支持路由和 REST API</li><li><strong>数据访问</strong>: 数据库连接和 Redis 集成</li><li><strong>WebSocket 支持</strong>: 实时通信能力</li><li><strong>CLI 工具</strong>: 快速生成项目的命令行界面</li><li><strong>外部化配置</strong>: 基于属性的配置管理</li></ul><h3 id="为什么选择-nanoboot" tabindex="-1">为什么选择 NanoBoot？ <a class="header-anchor" href="#为什么选择-nanoboot" aria-label="Permalink to &quot;为什么选择 NanoBoot？&quot;">​</a></h3><ul><li><strong>轻量级</strong>: 比 Spring Boot 更小的体积</li><li><strong>熟悉易用</strong>: 使用与 Spring 类似的注解和模式</li><li><strong>模块化</strong>: 只需选择需要的组件</li><li><strong>启动迅速</strong>: 更快的应用启动时间</li><li><strong>学习曲线平缓</strong>: 如果你了解 Spring，那么你已经了解 NanoBoot</li></ul><h3 id="架构概览" tabindex="-1">架构概览 <a class="header-anchor" href="#架构概览" aria-label="Permalink to &quot;架构概览&quot;">​</a></h3><p>NanoBoot 采用模块化架构构建：</p><ul><li><strong>nano-boot-core</strong>: 核心依赖注入容器</li><li><strong>nano-boot-starter</strong>: 应用程序引导和注解处理</li><li><strong>nano-boot-web</strong>: Web 服务器和 HTTP 路由</li><li><strong>nano-boot-data</strong>: 数据访问层，支持数据库和 Redis</li><li><strong>nano-boot-websocket</strong>: WebSocket 通信</li><li><strong>nano-boot-cli</strong>: 用于项目生成的命令行界面</li></ul><p>每个模块都可以独立使用或组合起来创建全功能的应用程序。</p>',12)])])}const b=t(e,[["render",i]]);export{u as __pageData,b as default};
